mapper.select:
select wl.*, a.name_cn as anime_name_cn, a.cover_url as anime_cover_url
from watch_log wl
inner join anime a on wl.anime_id = a.id

    wl.user_id = #{userId}

        and wl.anime_id = #{animeId}


        and wl.watch_date >= #{startDate}


        and wl.watch_date <= #{endDate}


order by wl.watch_date desc, wl.created_at desc
